async function updateColumn(
  id: string,
  data: {
    name?: string;
    icon?: string | null;
    color?: string | null;
    isFinal?: boolean;
  },
) {
  const existing = await db.query.columnTable.findFirst({
    where: eq(columnTable.id, id),
  });

  if (!existing) {
    throw new HTTPException(404, { message: "Column not found" });
  }

  const [updated] = await db
    .update(columnTable)
    .set({
      ...(data.name !== undefined && { name: data.name }),
      ...(data.icon !== undefined && { icon: data.icon }),
      ...(data.color !== undefined && { color: data.color }),
      ...(data.isFinal !== undefined && { isFinal: data.isFinal }),
    })
    .where(eq(columnTable.id, id))
    .returning();

  if (!updated) {
    throw new HTTPException(500, { message: "Failed to update column" });
  }

  return updated;
}

export default updateColumn;

export async function parseBody(req: Request): Promise<Record<string, unknown>> {
  const contentType = req.headers.get('content-type')

  switch (contentType) {
    case 'application/graphql':
      return { query: await req.text() }
    case 'application/json':
      try {
        return await req.json()
      } catch (e) {
        if (e instanceof Error) {
          console.error(`${e.stack || e.message}`)
        }
        throw Error(`POST body sent invalid JSON: ${e}`)
      }
    case 'application/x-www-form-urlencoded':
      return parseFormURL(req)
  }

  return {}
}

const parseFormURL = async (req: Request) => {
  const text = await req.text()
  const searchParams = new URLSearchParams(text)
  const res: { [params: string]: string } = {}
  searchParams.forEach((v, k) => (res[k] = v))
  return res
}

import { HTTPException } from 'hono/http-exception'
import { toQueryParams } from '../../utils/objectToQuery'
import type { XErrorResponse, XTokenResponse } from './types'

export async function refreshToken(
  client_id: string,
  client_secret: string,
  refresh_token: string
): Promise<XTokenResponse> {
  const authToken = btoa(`${encodeURIComponent(client_id)}:${encodeURIComponent(client_secret)}`)
  const params = toQueryParams({
    grant_type: 'refresh_token',
    refresh_token: refresh_token,
  })

  const response = (await fetch(`https://api.twitter.com/2/oauth2/token?${params}`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
      Authorization: `Basic ${authToken}`,
    },
  }).then((res) => res.json())) as XTokenResponse | XErrorResponse

  if ('error_description' in response) {
    throw new HTTPException(400, { message: response.error_description })
  }

  return response
}

import { HTTPException } from 'hono/http-exception'
import { toQueryParams } from '../../utils/objectToQuery'
import type { XErrorResponse, XRevokeResponse } from './types'

export async function revokeToken(
  client_id: string,
  client_secret: string,
  token: string
): Promise<boolean> {
  const authToken = btoa(`${encodeURIComponent(client_id)}:${encodeURIComponent(client_secret)}`)
  const params = toQueryParams({
    token,
    token_type_hint: 'access_token',
  })

  const response = (await fetch(`https://api.twitter.com/2/oauth2/revoke?${params}`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
      Authorization: `Basic ${authToken}`,
    },
  }).then((res) => res.json())) as XRevokeResponse | XErrorResponse

  if ('error_description' in response) {
    throw new HTTPException(400, { message: response.error_description })
  }

  return response.revoked
}

