import { createAuthConfig } from '@deepcrawl/auth/configs/auth.config';
import { betterAuth } from 'better-auth';

export function createAuth(env: CloudflareBindings) {
  const authConfigs = createAuthConfig({
    ...env,
    IS_WORKERD: true,
  });

  return betterAuth({
    ...authConfigs,
    secondaryStorage: {
      get: async (key: string) => {
        const value = await env.DEEPCRAWL_AUTH_KV.get(key);
        return value;
      },
      set: async (key: string, value: string, ttl?: number) => {
        if (typeof ttl === 'number' && Number.isFinite(ttl)) {
          const expirationTtl = Math.max(60, ttl);
          await env.DEEPCRAWL_AUTH_KV.put(key, value, { expirationTtl });
        } else {
          await env.DEEPCRAWL_AUTH_KV.put(key, value);
        }
      },
      delete: async (key: string) => {
        await env.DEEPCRAWL_AUTH_KV.delete(key);
      },
    },
    rateLimit: {
      ...authConfigs.rateLimit,
      storage: 'secondary-storage',
    },
  });
}

import { normalize } from 'node:path'

export type Options = {
  entry: string[]
}

const normalizePaths = (paths: string[]) => {
  return paths.map((p) => {
    let normalizedPath = normalize(p).replace(/\\/g, '/')
    if (normalizedPath.startsWith('./')) {
      normalizedPath = normalizedPath.substring(2)
    }
    return '/' + normalizedPath
  })
}

export const getEntryContent = async (options: Options) => {
  const globStr = normalizePaths(options.entry)
    .map((e) => `'${e}'`)
    .join(',')
  const appStr = `const modules = import.meta.glob([${globStr}], { import: 'default', eager: true })
      let added = false
      for (const [, app] of Object.entries(modules)) {
        if (app) {
          worker.route('/', app)
          worker.notFound(app.notFoundHandler)
          added = true
        }
      }
      if (!added) {
        throw new Error("Can't import modules from [${globStr}]")
      }
      `

  return `import { Hono } from 'hono'

const worker = new Hono()

${appStr}

export default worker`
}

